const results = [];
const summaries = items[0].json.accountSummaries;

for (const accountSummary of summaries) {
  // 계정 ID 추출 (형식: accounts/101423321)
  const currentAccountId = accountSummary.account.split('/')[1];

  // 필터 조건 1: 지정된 계정 ID가 아니면 이 계정의 모든 프로퍼티 무시
  if (currentAccountId !== targetAccountId) continue;

  if (accountSummary.propertySummaries) {
    for (const property of accountSummary.propertySummaries) {
      const propertyPath = property.property; // "properties/XXXXX"
      const displayName = property.displayName;

      // 필터 조건 2: 제외 리스트에 포함되는가?
      if (excludedProperties.includes(propertyPath)) continue;

      // 필터 조건 3: 'Subproperty' 키워드 포함 여부 (대소문자 무시)
      if (displayName.toLowerCase().includes('subproperty')) continue;

      results.push({
        json: {
          accountId: currentAccountId,
          propertyId: propertyPath.split('/')[1],
          propertyName: displayName
        }
      });
    }
  }
}

return results;


